+/// Generate a ranking (Vec of unique IDs) for kendall_tau tests.
+fn arb_ranking(max_len: usize) -> impl Strategy<Value = Vec<u64>> {
+    proptest::collection::hash_set(1u64..=50, 0..=max_len)
+        .prop_map(|s| s.into_iter().collect::<Vec<u64>>())
+}
